// Fetch RSS feeds and extract trending topics
const feeds = [
  { name: 'CISA', url: 'https://www.cisa.gov/cybersecurity-advisories/all.xml' },
  { name: 'Dark Reading', url: 'https://www.darkreading.com/rss.xml' },
  { name: 'Krebs', url: 'https://krebsonsecurity.com/feed/' },
  { name: 'Bleeping Computer', url: 'https://www.bleepingcomputer.com/feed/' }
];

const results = [];

for (const feed of feeds) {
  try {
    const response = await this.helpers.httpRequest({
      method: 'GET',
      url: feed.url,
      timeout: 10000
    });

    // Extract titles from RSS (basic XML parsing)
    const titleMatches = response.match(/<title><!\[CDATA\[([^\]]+)\]\]><\/title>|<title>([^<]+)<\/title>/gi) || [];

    const titles = titleMatches
      .map(t => t.replace(/<\/?title>|<!\[CDATA\[|\]\]>/gi, '').trim())
      .filter(t => t.length > 10)
      .slice(0, 10); // Top 10 from each feed

    results.push(...titles.map(title => ({
      feed: feed.name,
      title,
      timestamp: new Date().toISOString()
    })));
  } catch (error) {
    console.log(`Failed to fetch ${feed.name}: ${error.message}`);
  }
}

console.log(`Fetched ${results.length} total RSS items`);

// Extract trending keywords/topics
const keywords = [];
const topicPatterns = [
  /breach/i, /hack/i, /vulnerability/i, /ransomware/i,
  /zero.trust/i, /compliance/i, /HIPAA/i, /audit/i,
  /IoT/i, /privacy/i, /social.media/i, /healthcare/i,
  /identity/i, /IAM/i, /authentication/i
];

for (const item of results) {
  for (const pattern of topicPatterns) {
    if (pattern.test(item.title)) {
      const match = item.title.match(pattern)[0].toLowerCase();
      keywords.push(match);
    }
  }
}

// Count keyword frequency
const keywordCount = {};
keywords.forEach(k => {
  keywordCount[k] = (keywordCount[k] || 0) + 1;
});

// Sort by frequency
const trending = Object.entries(keywordCount)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map(([keyword, count]) => ({ keyword, count }));

console.log('Trending topics:', trending);

return {
  rssItems: results,
  trendingTopics: trending,
  topKeywords: trending.map(t => t.keyword)
};

// SQLite-based document selection with trending topic matching

// Import SQLite (n8n has sqlite3 available)
const sqlite3 = require('sqlite3');
const dbPath = '/home/claude/linkedin_content.db';

// Get trending keywords from previous node
const trendingKeywords = $json.topKeywords || [];
console.log('Trending keywords:', trendingKeywords);

// Open database connection
const db = new sqlite3.Database(dbPath);

// Query for available documents (not used yet)
const availableDocs = await new Promise((resolve, reject) => {
  db.all(`
    SELECT 
      d.id,
      d.folder_name,
      d.file_path,
      d.folder_topic,
      d.topics,
      d.keywords,
      d.last_used,
      d.use_count,
      COUNT(p.id) as post_count
    FROM documents d
    LEFT JOIN posts p ON d.id = p.document_id AND p.status IN ('approved', 'posted')
    WHERE d.status = 'available'
    GROUP BY d.id
    ORDER BY d.last_used ASC NULLS FIRST, d.use_count ASC
  `, (err, rows) => {
    if (err) reject(err);
    else resolve(rows);
  });
});

db.close();

console.log(`Found ${availableDocs.length} available documents in database`);

if (availableDocs.length === 0) {
  throw new Error('No available documents found in database!');
}

// Score documents based on keyword match with trending topics
const scoredDocs = availableDocs.map(doc => {
  let score = 0;
  let matchedKeywords = [];

  const docTopics = doc.topics ? JSON.parse(doc.topics) : [];
  const docKeywords = doc.keywords ? doc.keywords.split(', ') : [];

  for (const trending of trendingKeywords) {
    const trendingLower = trending.toLowerCase();

    // Check keywords
    for (const keyword of docKeywords) {
      if (keyword.includes(trendingLower) || trendingLower.includes(keyword)) {
        score += 10;
        matchedKeywords.push(trending);
      }
    }

    // Check topics
    for (const topic of docTopics) {
      if (topic.toLowerCase().includes(trendingLower) || trendingLower.includes(topic.toLowerCase())) {
        score += 5;
        matchedKeywords.push(trending);
      }
    }
  }

  return {
    id: doc.id,
    folder: doc.folder_name,
    path: doc.file_path,
    folder_topic: doc.folder_topic,
    topics: docTopics,
    keywords: docKeywords,
    use_count: doc.use_count,
    post_count: doc.post_count,
    relevanceScore: score,
    matchedKeywords: [...new Set(matchedKeywords)]
  };
});

// Sort by relevance score (highest first)
scoredDocs.sort((a, b) => b.relevanceScore - a.relevanceScore);

// Select the best match, or least-used if no good match
let selectedDoc;
if (scoredDocs[0].relevanceScore > 0) {
  selectedDoc = scoredDocs[0];
  console.log(`Selected TRENDING document: ${selectedDoc.folder} (score: ${selectedDoc.relevanceScore})`);
} else {
  // No trending match, select least-used document
  selectedDoc = scoredDocs[0];
  console.log(`Selected LEAST-USED document: ${selectedDoc.folder} (used ${selectedDoc.use_count} times)`);
}

return {
  ...selectedDoc,
  trendingTopics: trendingKeywords,
  availableCount: availableDocs.length,
  selectionReason: selectedDoc.relevanceScore > 0 ? 'trending_match' : 'least_used'
};

// Parse XML and find first .md or .docx file
const xml = $input.item.json.data;
const responsePattern = /<d:response>([\s\S]*?)<\/d:response>/g;
const files = [];
let match;

while ((match = responsePattern.exec(xml)) !== null) {
  const responseBlock = match[1];
  const hrefMatch = responseBlock.match(/<d:href>(.*?)<\/d:href>/);
  if (!hrefMatch) continue;

  const href = hrefMatch[1];
  const isFolder = responseBlock.includes('<d:collection');

  if (!isFolder && (href.endsWith('.md') || href.endsWith('.docx'))) {
    files.push(href);
  }
}

if (files.length === 0) {
  throw new Error('No .md or .docx files found in folder');
}

// Select first file
const selectedFile = files[0];
console.log(`Selected file: ${selectedFile}`);

return {
  ...$json,
  selectedFile,
  downloadUrl: 'https://nextcloud.local.example.home' + selectedFile
};

// Extract file content (assuming text/markdown for now)
const fileContent = $input.item.binary?.data ? 
  Buffer.from($input.item.binary.data.data, 'base64').toString('utf-8') :
  $input.item.json.data || '';

if (!fileContent || fileContent.length < 50) {
  throw new Error('File content is empty or too short');
}

console.log(`Extracted ${fileContent.length} characters of content`);

return {
  ...$json,
  fileContent: fileContent.substring(0, 15000), // Limit to 15k chars for Claude
  contentLength: fileContent.length
};

