// Update SQLite database to mark document as used

const sqlite3 = require('sqlite3');
const dbPath = '/home/claude/linkedin_content.db';
const documentId = $('Select Document (Intelligent)').item.json.id;
const folder = $('Select Document (Intelligent)').item.json.folder;
const postContent = $('Extract Generated Post').item.json.generatedPost;

const db = new sqlite3.Database(dbPath);

try {
  // Update document last_used and use_count
  await new Promise((resolve, reject) => {
    db.run(`
      UPDATE documents 
      SET last_used = datetime('now'),
          use_count = use_count + 1
      WHERE id = ?
    `, [documentId], (err) => {
      if (err) reject(err);
      else resolve();
    });
  });

  // Insert post record
  await new Promise((resolve, reject) => {
    db.run(`
      INSERT INTO posts (document_id, post_content, status, posted_at)
      VALUES (?, ?, 'approved', datetime('now'))
    `, [documentId, postContent], (err) => {
      if (err) reject(err);
      else resolve();
    });
  });

  db.close();

  console.log(`✓ Marked document ${folder} as used in database`);
  return { success: true, folder, action: 'approved', documentId };

} catch (error) {
  db.close();
  console.error('Error updating database:', error.message);
  return { success: false, error: error.message };
}
